$(document).ready(function () {

    var baseUrl = window.location.origin;
    let retrive_data = baseUrl + '/ca_report_ako_jama_ajax';

    let grandTotals = {
        Akki: 0,
        Kai: 0,
        Oil: 0
    };

    var table = $('#ca-report-ako-jama').DataTable({
        processing: true,
        serverSide: true,
        destroy: true,
        dom: 'Bfrtip',

        buttons: [

            // ================== ✅ EXCEL ==================
            {
                extend: 'excelHtml5',
                text: 'Export to Excel',
                filename: 'CA_Report_AKO_Jama',

                action: function (e, dt, button, config) {

                    var self = this;

                    dt.one('preXhr', function (e, s, data) {
                        data.length = -1;
                    });

                    dt.one('draw', function () {
                        $.fn.dataTable.ext.buttons.excelHtml5.action.call(self, e, dt, button, config);

                        dt.one('preXhr', function (e, s, data) {
                            data.length = 10;
                        });

                        setTimeout(function () {
                            dt.ajax.reload();
                        }, 100);
                    });

                    dt.ajax.reload();
                },

                customize: function (xlsx) {

                    var sheet = xlsx.xl.worksheets['sheet1.xml'];
                    var sheetData = $('sheetData', sheet);

                    // ✅ Get Financial Year
                    var financial_year = $('.financial_year option:selected').text() || '';

                    // ✅ Title
                    $('c[r=A1] t', sheet).text('AKO Jama Report');

                    // ✅ Last row
                    var lastRow = $('sheetData row', sheet).length + 1;

                    // ✅ Grand Total Row
                    sheetData.append(`
                        <row r="${lastRow}">
                            <c t="inlineStr" s="2" r="B${lastRow}">
                                <is><t>Grand Total</t></is>
                            </c>
                            <c t="n" s="2" r="C${lastRow}">
                                <v>${grandTotals.Akki}</v>
                            </c>
                            <c t="n" s="2" r="D${lastRow}">
                                <v>${grandTotals.Kai}</v>
                            </c>
                            <c t="n" s="2" r="E${lastRow}">
                                <v>${grandTotals.Oil}</v>
                            </c>
                        </row>
                    `);

                    // ================== ✅ FINANCIAL YEAR ==================

                    var fyRow = lastRow + 2;

                    sheetData.append(`
                        <row r="${fyRow}">
                            <c t="inlineStr" s="2" r="A${fyRow}">
                                <is><t>Financial Year : ${financial_year}</t></is>
                            </c>
                        </row>
                    `);

                    // ✅ Merge full width (A to E)
                    if (!$('mergeCells', sheet).length) {
                        $('worksheet', sheet).append('<mergeCells></mergeCells>');
                    }

                    $('mergeCells', sheet).append(`<mergeCell ref="A${fyRow}:E${fyRow}"/>`);
                }
            },

            // ================== ✅ PDF ==================
            {
                extend: 'pdfHtml5',
                text: 'Export to PDF',
                filename: 'CA_Report_AKO_Jama',

                action: function (e, dt, button, config) {

                    var self = this;

                    dt.one('preXhr', function (e, s, data) {
                        data.length = -1;
                    });

                    dt.one('draw', function () {

                        $.fn.dataTable.ext.buttons.pdfHtml5.action.call(self, e, dt, button, config);

                        dt.one('preXhr', function (e, s, data) {
                            data.length = 10;
                        });

                        setTimeout(function () {
                            dt.ajax.reload();
                        }, 100);
                    });

                    dt.ajax.reload();
                },

                customize: function (doc) {

                    var financial_year = $('.financial_year option:selected').text() || '';

                    // ✅ Title
                    doc.content.splice(0, 0, {
                        text: 'AKO Jama Report',
                        fontSize: 14,
                        bold: true,
                        alignment: 'center',
                        margin: [0, 0, 0, 10]
                    });

                    var table = doc.content.find(item => item.table);

                    if (table) {
                        table.table.widths = ['auto', '*', 'auto', 'auto', 'auto'];
                        table.margin = [20, 0, 20, 0];

                        table.table.body.forEach(function (row, i) {
                            row.forEach(function (cell) {
                                cell.alignment = (i === 0) ? 'center' : 'left';
                            });
                        });

                        table.layout = {
                            hLineWidth: () => 0.5,
                            vLineWidth: () => 0.5,
                            hLineColor: () => '#aaa',
                            vLineColor: () => '#aaa',
                            paddingLeft: () => 6,
                            paddingRight: () => 6
                        };
                    }

                    // ✅ Grand Total
                    doc.content.push({
                        text: `Grand Total | Akki: ${grandTotals.Akki} | Kai: ${grandTotals.Kai} | Oil: ${grandTotals.Oil}`,
                        alignment: 'center',
                        margin: [0, 10, 0, 5],
                        bold: true
                    });

                    // ✅ Financial Year only
                    doc.content.push({
                        text: 'Financial Year : ' + financial_year,
                        alignment: 'left',
                        margin: [0, 5, 0, 0],
                        bold: true
                    });
                }
            }
        ],

        ajax: {
            url: retrive_data,
            data: function (d) {
                d.financial_year = $('.financial_year').val();
            },
            dataSrc: function (json) {

                if (json.grand_total) {
                    grandTotals.Akki = json.grand_total.Akki;
                    grandTotals.Kai  = json.grand_total.Kai;
                    grandTotals.Oil  = json.grand_total.Oil;
                }

                return json.data;
            }
        },

        columns: [
            {
                data: null,
                render: function (data, type, row, meta) {
                    return meta.row + 1;
                }
            },
            { data: "subcategory_name" },
            { data: "Akki" },
            { data: "Kai" },
            { data: "Oil" }
        ],

        footerCallback: function () {
            var api = this.api();
            var json = api.ajax.json();

            if (json && json.grand_total) {
                $(api.column(2).footer()).html(json.grand_total.Akki);
                $(api.column(3).footer()).html(json.grand_total.Kai);
                $(api.column(4).footer()).html(json.grand_total.Oil);
            }
        }
    });

    // ✅ FILTER BUTTON
    $('.submit_purchase_report').click(function () {
        table.ajax.reload();
    });

});